}

{
  "vulnerable": true,
  "cwe": "CWE-483",
  "location": "The `square` function modifies the input pointer, which is not allowed in C.",
  "explanation": "This vulnerability occurs because the `square` function takes a pointer to an integer and attempts to modify it. This can lead to undefined behavior if the pointer is not properly managed."
}

{
  "vulnerable": true,
  "cwe": "CWE-28",
  "location": "Inserting user data into a database table",
