}

{
  "vulnerable": true,
  "cwe": "CWE-293",
  "location": "The `process` function modifies the input array, which is not safe for concurrent access.",
  "explanation": "This vulnerability occurs because the `process` function modifies the input array, which can lead to undefined behavior if multiple threads or processes are accessing it simultaneously."
}

{
  "vulnerable": true,
  "cwe": "CWE-123",
